// Fire a progress update only at 10% milestones.
// $runIndex increments each time this node executes (0-based).
const total = $('Identify Unproccessed Artifacts').all().length;
const stepSize = Math.max(1, Math.round(total * 0.1));
const iteration = $runIndex + 1; // 1-based
const runId = $('Create Run Id').first().json.run_id;

if (iteration % stepSize === 0) {
  return [{ json: { run_id: runId, progress_count: iteration } }];
}
return [];

